import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../services/api';
import './AdminAnalytics.css';

function AdminAnalytics() {
  const { user } = useAuth();
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [period, setPeriod] = useState('week');

  // Данные
  const [summary, setSummary] = useState(null);
  const [views, setViews] = useState(null);
  const [prices, setPrices] = useState(null);
  const [closed, setClosed] = useState(null);

  useEffect(() => {
    loadData();
  }, [period]);

  const loadData = async () => {
    setLoading(true);
    setError(null);

    try {
      // Загружаем все данные
      const [summaryRes, viewsRes, pricesRes, closedRes] = await Promise.all([
        API.get('/analytics/summary'),
        API.get(`/analytics/views?period=${period}`),
        API.get('/analytics/prices'),
        API.get(`/analytics/closed?period=${period}`)
      ]);

      setSummary(summaryRes.data);
      setViews(viewsRes.data);
      setPrices(pricesRes.data);
      setClosed(closedRes.data);

    } catch (err) {
      console.error('Ошибка:', err);
      setError('Не удалось загрузить данные');
    } finally {
      setLoading(false);
    }
  };

  

  if (loading) return <div className="loader">Загрузка...</div>;
  if (error) return <div className="error">{error}</div>;

  return (
    <div className="analytics-page">
      <h1>📊 Аналитика</h1>

      {/* Кнопки периода - черный текст, серый фон при наведении */}
      <div className="period-selector">
        <button
          className={period === 'day' ? 'active' : ''}
          onClick={() => setPeriod('day')}
        >
          День
        </button>
        <button
          className={period === 'week' ? 'active' : ''}
          onClick={() => setPeriod('week')}
        >
          Неделя
        </button>
        <button
          className={period === 'month' ? 'active' : ''}
          onClick={() => setPeriod('month')}
        >
          Месяц
        </button>
      </div>

      {/* Сводка */}
      {summary && (
        <div className="metrics-grid">
          <div className="metric-card">
            <h3>Всего объявлений</h3>
            <p className="metric-value">{summary.total_listings}</p>
          </div>
          <div className="metric-card">
            <h3>Активных сегодня</h3>
            <p className="metric-value">{summary.active_today}</p>
          </div>
          <div className="metric-card">
            <h3>Просмотров сегодня</h3>
            <p className="metric-value">{summary.views_today}</p>
          </div>
          <div className="metric-card">
            <h3>Новых сегодня</h3>
            <p className="metric-value">{summary.new_today}</p>
          </div>
        </div>
      )}

      {/* Просмотры */}
      {views && (
        <div className="analytics-card">
          <h2>👁 Просмотры за {period}</h2>
          <div className="stats-grid">
            <div className="stat-item">
              <span className="stat-label">Всего просмотров:</span>
              <span className="stat-value">{views.total_views}</span>
            </div>
            <div className="stat-item">
              <span className="stat-label">Уникальных объявлений:</span>
              <span className="stat-value">{views.unique_listings}</span>
            </div>
          </div>
        </div>
      )}

      {/* Цены */}
      {prices && (
        <div className="analytics-card">
          <h2>💰 Цены (активные объявления)</h2>
          <div className="stats-grid">
            <div className="stat-item">
              <span className="stat-label">Всего активных:</span>
              <span className="stat-value">{prices.total_active}</span>
            </div>
            <div className="stat-item">
              <span className="stat-label">Средняя цена:</span>
              <span className="stat-value">{prices.avg_price.toLocaleString()} ₽</span>
            </div>
            <div className="stat-item">
              <span className="stat-label">Цена за м²:</span>
              <span className="stat-value">{prices.avg_price_per_m2.toLocaleString()} ₽</span>
            </div>
          </div>

          {prices.by_type.length > 0 && (
            <>
              <h3>По типам</h3>
              <table className="stats-table">
                <thead>
                  <tr>
                    <th>Тип</th>
                    <th>Кол-во</th>
                    <th>Ср. цена</th>
                    <th>₽/м²</th>
                  </tr>
                </thead>
                <tbody>
                  {prices.by_type.map((item, idx) => (
                    <tr key={idx}>
                      <td>{item.type}</td>
                      <td>{item.count}</td>
                      <td>{item.avg_price.toLocaleString()} ₽</td>
                      <td>{item.avg_price_per_m2.toLocaleString()} ₽</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </>
          )}
        </div>
      )}

      {/* Закрытые сделки */}
      {closed && (
        <div className="analytics-card">
          <h2>✅ Закрытые сделки за {period}</h2>
          <div className="stats-grid">
            <div className="stat-item">
              <span className="stat-label">Продано:</span>
              <span className="stat-value">{closed.total_closed}</span>
            </div>
            <div className="stat-item">
              <span className="stat-label">Выручка:</span>
              <span className="stat-value">{closed.total_revenue.toLocaleString()} ₽</span>
            </div>
          </div>

          {closed.by_type.length > 0 && (
            <>
              <h3>По типам</h3>
              <table className="stats-table">
                <thead>
                  <tr>
                    <th>Тип</th>
                    <th>Кол-во</th>
                    <th>Ср. цена</th>
                    <th>Выручка</th>
                  </tr>
                </thead>
                <tbody>
                  {closed.by_type.map((item, idx) => (
                    <tr key={idx}>
                      <td>{item.type}</td>
                      <td>{item.count}</td>
                      <td>{item.avg_price.toLocaleString()} ₽</td>
                      <td>{item.total_revenue.toLocaleString()} ₽</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </>
          )}
        </div>
      )}
    </div>
  );
}

export default AdminAnalytics;
